    <script>
        let currentStep = 1;
        const totalSteps = 4;

        // Email validation
        document.getElementById('email').addEventListener('blur', function() {
            const email = this.value;
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            const errorElement = document.getElementById('emailError');

            if (email && !emailRegex.test(email)) {
                this.classList.add('error');
                errorElement.classList.add('show');
            } else {
                this.classList.remove('error');
                errorElement.classList.remove('show');
            }
        });

        function selectTicket(type) {
            // Remove selected class from all cards
            document.querySelectorAll('.ticket-card').forEach(card => {
                card.classList.remove('selected');
            });

            // Add selected class to clicked card
            event.currentTarget.classList.add('selected');

            // Check the radio button
            document.getElementById('ticket' + type.charAt(0).toUpperCase() + type.slice(1)).checked = true;

            // Update total
            updateTotal();

            // Clear error
            document.getElementById('ticketError').classList.remove('show');
            document.querySelectorAll('.ticket-card').forEach(card => {
                card.style.border = '';
            });
        }

        function updateTotal() {
            let total = 0;

            // Get selected ticket price
            const selectedTicket = document.querySelector('input[name="ticket"]:checked');
            if (selectedTicket) {
                switch(selectedTicket.value) {
                    case 'general': total += 199; break;
                    case 'vip': total += 499; break;
                    case 'speaker': total += 0; break;
                }
            }

            // Add addon prices
            if (document.getElementById('workshop').checked) total += 99;
            if (document.getElementById('dinner').checked) total += 49;
            if (document.getElementById('tshirt').checked) total += 25;

            document.getElementById('totalAmount').textContent = '$' + total;
        }

        function toggleOtherDietary() {
            const select = document.getElementById('dietary');
            const otherDiv = document.getElementById('dietaryOther');

            if (select.value === 'other') {
                otherDiv.classList.add('show');
            } else {
                otherDiv.classList.remove('show');
                document.getElementById('dietaryOtherText').value = '';
            }
        }

        function updateCharCounter() {
