            } else {
                otherDiv.classList.remove('show');
            }
        });

        // Character counter
        document.getElementById('specialRequests').addEventListener('input', function() {
            const remaining = 500 - this.value.length;
            const counter = document.getElementById('char-counter');
            counter.textContent = remaining + ' characters remaining';

            if (remaining < 50) {
                counter.classList.add('warning');
            } else {
                counter.classList.remove('warning');
            }
        });

        // Navigation
        document.getElementById('next-btn').addEventListener('click', nextStep);
        document.getElementById('back-btn').addEventListener('click', prevStep);

        function nextStep() {
            if (validateCurrentStep()) {
                if (currentStep < totalSteps) {
                    currentStep++;
                    showStep(currentStep);
                } else {
                    // Final registration
                    alert('Registration completed successfully!');
                }
            }
        }

        function prevStep() {
            if (currentStep > 1) {
                currentStep--;
                showStep(currentStep);
            }
        }

        function showStep(step) {
            // Hide all steps
            document.querySelectorAll('.step').forEach(s => s.classList.remove('active'));

            // Show current step
            document.getElementById('step-' + step).classList.add('active');

            // Update progress indicator
            updateProgressIndicator();

            // Update navigation buttons
            updateNavigationButtons();

            // Update review if on step 4
            if (step === 4) {
                updateReview();
            }
        }

        function updateProgressIndicator() {
            for (let i = 1; i <= totalSteps; i++) {
                const circle = document.getElementById('circle-' + i);
                const connector = document.getElementById('connector-' + i);

                if (i < currentStep) {
                    circle.className = 'step-circle completed';
                    if (connector) connector.className = 'step-connector completed';
                } else if (i === currentStep) {
                    circle.className = 'step-circle current';
                    if (connector) connector.className = 'step-connector';
                } else {
                    circle.className = 'step-circle future';
                    if (connector) connector.className = 'step-connector';
                }
            }
        }

        function updateNavigationButtons() {
            const backBtn = document.getElementById('back-btn');
            const nextBtn = document.getElementById('next-btn');

            if (currentStep === 1) {
                backBtn.classList.add('hidden');
            } else {
                backBtn.classList.remove('hidden');
            }

            if (currentStep === totalSteps) {
                nextBtn.textContent = 'Register';
                nextBtn.className = 'btn btn-success';
            } else {
                nextBtn.textContent = 'Next';
                nextBtn.className = 'btn btn-primary';
            }
        }

        function validateCurrentStep() {
            let isValid = true;

            if (currentStep === 1) {
                // Validate personal info
                const requiredFields = ['firstName', 'lastName', 'email', 'phone', 'jobTitle', 'company'];

                requiredFields.forEach(fieldId => {
                    const field = document.getElementById(fieldId);
                    const error = document.getElementById(fieldId + '-error');
                    const formGroup = field.closest('.form-group');

                    if (!field.value.trim()) {
                        field.classList.add('error');
                        error.classList.add('show');
                        error.textContent = 'This field is required';
                        formGroup.classList.add('has-error');
                        isValid = false;
                    } else {
                        field.classList.remove('error');
                        error.classList.remove('show');
                        formGroup.classList.remove('has-error');
                    }
                });

                // Special validation for email
                if (document.getElementById('email').value.trim()) {
                    isValid = validateEmail() && isValid;
                }

            } else if (currentStep === 2) {
